# Streaming version using ordered dict
def streaming_first_unique(stream):
    from collections import OrderedDict
    seen_once = OrderedDict()
    seen_more = set()
    for ch in stream:
        if ch in seen_more:
            continue
        if ch in seen_once:
            del seen_once[ch]
            seen_more.add(ch)
        else:
            seen_once[ch] = True
    return next(iter(seen_once), None)

