def exist(board, word):
    rows, cols = len(board), len(board[0])

    def dfs(r, c, idx):
        if idx == len(word):
            return True
        if r < 0 or r >= rows or c < 0 or c >= cols or board[r][c] != word[idx]:
            return False
        tmp = board[r][c]
        board[r][c] = '#'
        found = (dfs(r+1, c, idx+1) or dfs(r-1, c, idx+1) or
                 dfs(r, c+1, idx+1) or dfs(r, c-1, idx+1))
        board[r][c] = tmp
        return found

    for r in range(rows):
        for c in range(cols):
            if board[r][c] == word[0] and dfs(r, c, 0):
                return True
    return False

def valid_ip_address(query_ip):
    def is_valid_ipv4(ip):
        parts = ip.split('.')
        if len(parts) != 4:
            return False
        for p in parts:
            if not p or not p.isdigit():
                return False
            if p != str(int(p)):  # catches leading zeros
                return False
            if not 0 <= int(p) <= 255:
                return False
        return True

    def is_valid_ipv6(ip):
        parts = ip.split(':')
        if len(parts) != 8:
            return False
        hex_chars = set('0123456789abcdefABCDEF')
        for p in parts:
            if not p or len(p) > 4:
                return False
            if not all(c in hex_chars for c in p):
                return False
        return True

    if is_valid_ipv4(query_ip):
        return 'IPv4'
    if is_valid_ipv6(query_ip):
        return 'IPv6'
    return 'Neither'

def encode(s):
    if not s:
        return ''
    result = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            result.append(str(count) + s[i-1])
            count = 1
    result.append(str(count) + s[-1])
    return ''.join(result)

