print(encode('aaaa'))      # '4a'

from collections import Counter

def find_pairs(nums, k):
    if k < 0:
        return 0
    count = Counter(nums)
    result = 0
    for num in count:
        if k == 0:
            if count[num] >= 2:
                result += 1
        else:
            if num + k in count:
                result += 1
    return result

print(find_pairs([3, 1, 4, 1, 5], 2))  # 2 -> (1,3) and (3,5)
print(find_pairs([1, 2, 3, 4, 5], 1))  # 4
print(find_pairs([1, 3, 1, 5, 4], 0))  # 1 -> only (1,1)
